package main

import (
    "fmt"
    "os"
)

func main() {
    // Create file
    file, err := os.Create("test.txt")
    if err != nil {
        fmt.Println("Error creating file:", err)
        return
    }
    defer file.Close()
    fmt.Println("File created successfully")

    // File info
    info, _ := os.Stat("test.txt")
    fmt.Printf("Name: %s, Size: %d bytes\n", info.Name(), info.Size())

    // Cleanup
    os.Remove("test.txt")
}
